const svg = $('#grpd-svg'), out = $('#grpd-out');
const bFull = $('#grpd-full'), bPi0 = $('#grpd-pi0');
let mode = 'full';
function render(){
  svg.innerHTML = '';
  if(mode === 'full'){
    // three isomorphic objects with automorphisms
    const pts = [{x:160,y:150,label:'E_1',aut:'Z/2'},{x:310,y:150,label:'E_2',aut:'Z/2'},{x:460,y:150,label:'E_3',aut:'Z/2'}];
    // iso arrows between pairs (curved, both directions)
    drawArrow(svg,[pts[0].x,pts[0].y],[pts[1].x,pts[1].y],{curve:-30,label:'φ',color:'var(--cyan)',markerId:'gg1'});
    drawArrow(svg,[pts[1].x,pts[1].y],[pts[0].x,pts[0].y],{curve:-30,label:'φ⁻¹',color:'var(--cyan)',markerId:'gg1b'});
    drawArrow(svg,[pts[1].x,pts[1].y],[pts[2].x,pts[2].y],{curve:-30,label:'ψ',color:'var(--cyan)',markerId:'gg2'});
    drawArrow(svg,[pts[2].x,pts[2].y],[pts[1].x,pts[1].y],{curve:-30,label:'ψ⁻¹',color:'var(--cyan)',markerId:'gg2b'});
    drawArrow(svg,[pts[0].x,pts[0].y],[pts[2].x,pts[2].y],{curve:80,label:'ψ∘φ',color:'var(--blue)',markerId:'gg3'});
    // automorphism loops
    for(const p of pts){
      drawLoop(svg, p.x, p.y, '[-1]', 'var(--yellow)', 'gg-l-'+p.label);
    }
    for(const p of pts){ drawNode(svg, p.x, p.y, p.label, {r:22, stroke:'var(--blue)'}); }
    out.textContent = 'groupoid: 3 objects, each with Aut = Z/2, all connected by isomorphisms.\niso classes π₀ = 1, but automorphism data persists at every object.';
  } else {
    // collapsed to single dot
    drawNode(svg, 310, 150, '[E]', {r:26, stroke:'var(--green)', textColor:'#fff'});
    const t = SVG('text',{x:310, y:210,'text-anchor':'middle','font-size':13, fill:'var(--mute)'});
    t.textContent = 'π₀ = { [E] }  — automorphism info lost';
    svg.appendChild(t);
    out.textContent = 'set view: a single iso class. The Z/2 automorphism at [E] has been forgotten.\nThis is what a moduli functor to Sets records.';
  }
}
bFull.addEventListener('click',()=>{ mode='full'; bFull.classList.add('active'); bPi0.classList.remove('active'); render(); });
bPi0.addEventListener('click',()=>{ mode='pi0'; bPi0.classList.add('active'); bFull.classList.remove('active'); render(); });
render();

