const svg = $('#descent-svg'), out = $('#descent-out');
const bGlue = $('#descent-glue'), bReset = $('#descent-reset'), bCoc = $('#descent-cocycle');
let state = 'local';
function render(){
  svg.innerHTML='';
  if(state === 'local' || state === 'glued'){
    // base: U (left oval), V (right oval), overlap in middle
    const uC = [180,200], vC = [440,200];
    svg.appendChild(SVG('ellipse',{cx:uC[0],cy:uC[1],rx:150,ry:60,fill:'none',stroke:'var(--blue)','stroke-width':1.5}));
    svg.appendChild(SVG('ellipse',{cx:vC[0],cy:vC[1],rx:150,ry:60,fill:'none',stroke:'var(--green)','stroke-width':1.5}));
    const lU = SVG('text',{x:80,y:200,'font-size':14,fill:'var(--blue)','font-weight':600}); lU.textContent='U'; svg.appendChild(lU);
    const lV = SVG('text',{x:540,y:200,'font-size':14,fill:'var(--green)','font-weight':600}); lV.textContent='V'; svg.appendChild(lV);
    const lUV = SVG('text',{x:310,y:275,'text-anchor':'middle','font-size':12,fill:'var(--mute)','font-style':'italic'}); lUV.textContent='U ∩ V'; svg.appendChild(lUV);
    // local families above
    if(state === 'local'){
      drawNode(svg, 180, 80, 'x_U', {r:22, stroke:'var(--blue)'});
      drawNode(svg, 440, 80, 'x_V', {r:22, stroke:'var(--green)'});
      drawArrow(svg,[202,80],[418,80],{label:'φ on U∩V',color:'var(--yellow)',markerId:'dc1',curve:-20});
      // restriction dashed arrows down to the overlap region
      drawArrow(svg,[180,102],[310,195],{color:'var(--mute)',dash:'4 3',markerId:'ddU'});
      drawArrow(svg,[440,102],[310,195],{color:'var(--mute)',dash:'4 3',markerId:'ddV'});
      out.textContent = 'Local data: x_U on U, x_V on V, transition iso φ : x_V|U∩V → x_U|U∩V.\nIf the stack condition holds, this glues.';
    } else {
      drawNode(svg, 310, 80, 'x  on  U ∪ V', {r:38, stroke:'var(--yellow)', fontSize:13});
      drawArrow(svg,[285,100],[180,180],{color:'var(--mute)',dash:'4 3',markerId:'dgU',label:'|_U'});
      drawArrow(svg,[335,100],[440,180],{color:'var(--mute)',dash:'4 3',markerId:'dgV',label:'|_V'});
      out.textContent = 'Glued! The descent datum (x_U, x_V, φ) produces a global x on U ∪ V, unique up to unique iso.\nThis is what the stack axiom guarantees.';
    }
  } else if(state === 'cocycle'){
    // Three circles representing U_i, U_j, U_k and their triple overlap
    const C = [{x:200,y:170,r:90,lab:'U_i',col:'var(--blue)'},
               {x:340,y:170,r:90,lab:'U_j',col:'var(--green)'},
               {x:270,y:260,r:90,lab:'U_k',col:'var(--pink)'}];
    for(const c of C) svg.appendChild(SVG('circle',{cx:c.x,cy:c.y,r:c.r,fill:'none',stroke:c.col,'stroke-width':1.3,opacity:0.7}));
    // labels
    svg.appendChild(Object.assign(SVG('text',{x:140,y:100,'font-size':13,fill:'var(--blue)','font-weight':600}),{textContent:'U_i'}));
    svg.appendChild(Object.assign(SVG('text',{x:410,y:100,'font-size':13,fill:'var(--green)','font-weight':600}),{textContent:'U_j'}));
    svg.appendChild(Object.assign(SVG('text',{x:260,y:365,'font-size':13,fill:'var(--pink)','font-weight':600}),{textContent:'U_k'}));
    // cocycle triangle at the triple overlap
    const a=[230,200], b=[310,200], c=[270,240];
    drawArrow(svg,a,b,{label:'φ_ij',color:'var(--yellow)',markerId:'c1',pad1:2,pad2:2});
    drawArrow(svg,b,c,{label:'φ_jk',color:'var(--yellow)',markerId:'c2',pad1:2,pad2:2});
    drawArrow(svg,a,c,{label:'φ_ik',color:'var(--cyan)',markerId:'c3',pad1:2,pad2:2,curve:30});
    const eq = SVG('text',{x:310,y:295,'font-size':13,fill:'var(--ink)'});
    eq.textContent = 'cocycle:  φ_ik = φ_ij ∘ φ_jk';
    svg.appendChild(eq);
    out.textContent = 'On triple overlaps U_i ∩ U_j ∩ U_k, the transition isomorphisms must compose consistently.\nThis cocycle condition is automatic for presheaves of sets but essential for groupoids.';
  }
}
bGlue.addEventListener('click',()=>{ state='glued'; render(); });
bReset.addEventListener('click',()=>{ state='local'; render(); });
bCoc.addEventListener('click',()=>{ state='cocycle'; render(); });
render();

