(function(){
  const svg = $('#bg-svg'), out = $('#bg-out');
  const selG = $('#bg-grp'), selR = $('#bg-ring');
  // For cyclic G = Z/n, |H^1(Spec F_q, G)| = gcd(n, q-1) when we use étale cohomology with constant sheaf?
  // Actually |Hom(Gal(F_q), Z/n)| = #(Z/n whose order divides... the absolute Galois group of F_q is Ẑ, so Hom(Ẑ, Z/n) = Z/n as a set.
  // So |H^1(Spec F_q, Z/n)_et| = n for any finite field. Simpler: Z/n-torsors on Spec F_q correspond to Z/n-covers, i.e. étale Z/n extensions of F_q, which is unique of each degree dividing n; total count = n.
  // For S_3 over F_q: H^1(Gal, S_3) (non-abelian) = conjugacy classes of homs from Ẑ to S_3 = conjugacy classes of elements of S_3 = 3 (id, transposition, 3-cycle).
  // For R: Gal(C/R) = Z/2. Hom(Z/2, Z/n) = elements of order dividing 2, so 2 if n even, 1 if n odd. For S_3: elts of order ≤2 up to conjugacy = 2 (id and transposition).
  function data(G, R){
    if(R === 'R'){
      if(G === 'Z2') return {n:2, classes:['trivial','sign: x²=-1'], aut:['Z/2','Z/2']};
      if(G === 'Z3') return {n:1, classes:['trivial'], aut:['Z/3']};
      if(G === 'S3') return {n:2, classes:['trivial','transposition'], aut:['S_3','Z/2']};
    }
    // finite field case: Galois group is Ẑ, so Hom to a finite group classified by conjugacy classes of elts (for non-abelian) or all elts (abelian)
    if(G === 'Z2') return {n:2, classes:['trivial','unique nontrivial Z/2-cover'], aut:['Z/2','Z/2']};
    if(G === 'Z3') return {n:3, classes:['trivial','Z/3-cover A','Z/3-cover B'], aut:['Z/3','Z/3','Z/3']};
    if(G === 'S3') return {n:3, classes:['trivial','transposition-type','3-cycle-type'], aut:['S_3','Z/2','Z/3']};
    return {n:1, classes:['?'], aut:['?']};
  }
  function render(){
    svg.innerHTML='';
    const d = data(selG.value, selR.value);
    const n = d.n;
    const W = 620, cy=100;
    for(let i=0;i<n;i++){
      const x = (W/(n+1))*(i+1);
      drawNode(svg, x, cy, `P_${i+1}`, {r:22, stroke:'var(--yellow)'});
      // automorphism loop
      drawLoop(svg, x, cy, 'Aut = '+d.aut[i], 'var(--cyan)', 'bg-l-'+i);
      // label underneath
      const t = SVG('text',{x, y:cy+55,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
      t.textContent = d.classes[i];
      svg.appendChild(t);
    }
    const title = SVG('text',{x:310, y:210,'text-anchor':'middle','font-size':13,fill:'var(--ink)'});
    title.textContent = `iso classes of ${selG.options[selG.selectedIndex].text}-torsors over Spec ${selR.options[selR.selectedIndex].text}: ${n}`;
    svg.appendChild(title);
    out.textContent = `π₀(BG(R)) has ${n} element${n===1?'':'s'}. At every object the automorphism group is a form of G.\nFor G abelian, π₀ = H¹(Spec R, G); for non-abelian G, it is the pointed set of 1-cocycles mod coboundary.`;
  }
  selG.addEventListener('change', render);
  selR.addEventListener('change', render);
  render();
})();

