const svg = $('#atlas-svg'), out = $('#atlas-out');
const bT = $('#atlas-toggle'), bR = $('#atlas-reset');
let show = false;
function render(){
  svg.innerHTML='';
  // stack at bottom as fuzzy oval
  svg.appendChild(SVG('ellipse',{cx:310,cy:240,rx:180,ry:40,fill:'none',stroke:'var(--violet)','stroke-width':1.5,'stroke-dasharray':'5 3'}));
  const lX = SVG('text',{x:500,y:245,'font-size':14,fill:'var(--violet)','font-weight':600}); lX.textContent='𝒳'; svg.appendChild(lX);
  // atlas scheme at top
  svg.appendChild(SVG('rect',{x:220,y:40,width:180,height:50,rx:6,fill:'none',stroke:'var(--yellow)','stroke-width':1.5}));
  const lSc = SVG('text',{x:310,y:72,'text-anchor':'middle','font-size':14,fill:'var(--yellow)','font-weight':600}); lSc.textContent='X (scheme)'; svg.appendChild(lSc);
  drawArrow(svg,[310,92],[310,200],{label:'étale surj.',color:'var(--yellow)',markerId:'at1'});
  if(show){
    // fiber product on upper-left
    svg.appendChild(SVG('rect',{x:40,y:130,width:130,height:45,rx:6,fill:'none',stroke:'var(--cyan)','stroke-width':1.5}));
    const lF = SVG('text',{x:105,y:158,'text-anchor':'middle','font-size':13,fill:'var(--cyan)','font-weight':600}); lF.textContent='X ×_𝒳 X'; svg.appendChild(lF);
    // two arrows to X
    drawArrow(svg,[170,145],[240,70],{label:'pr_1',color:'var(--cyan)',markerId:'at2'});
    drawArrow(svg,[170,165],[240,78],{label:'pr_2',color:'var(--cyan)',markerId:'at3',curve:-20});
    // note about automorphisms
    const note = SVG('text',{x:105,y:210,'text-anchor':'middle','font-size':11,fill:'var(--mute)','font-style':'italic'});
    note.textContent = 'points = pairs (x,y,φ:π(x)≅π(y))';
    svg.appendChild(note);
    out.textContent = 'The fiber product X ×_𝒳 X parametrises pairs of points in X with an isomorphism of their images in 𝒳.\nFor x = y, these are the automorphisms. For x ≠ y, these record overlap.\n(X ×_𝒳 X ⇒ X) is the groupoid object presenting 𝒳.';
  } else {
    out.textContent = 'A scheme X with an étale surjection to the stack 𝒳. This is an atlas.\nClick "show fiber product" to see the groupoid of overlaps.';
  }
}
bT.addEventListener('click',()=>{ show = !show; bT.textContent = show?'hide fiber product':'show fiber product'; render(); });
bR.addEventListener('click',()=>{ show = false; bT.textContent = 'show fiber product'; render(); });
render();

