let step = 0;
function render(){
  svg.innerHTML='';
  // nodes
  const mx = {x:140, y:100};
  const X  = {x:140, y:220};
  const Y  = {x:460, y:160};
  // stack
  svg.appendChild(SVG('ellipse',{cx:mx.x,cy:mx.y,rx:80,ry:28,fill:'none',stroke:'var(--violet)','stroke-width':1.5,'stroke-dasharray':'5 3'}));
  const lM = SVG('text',{x:mx.x,y:mx.y+5,'text-anchor':'middle','font-size':14,fill:'var(--violet)','font-weight':600}); lM.textContent='ℳ_{1,1}'; svg.appendChild(lM);
  // coarse
  svg.appendChild(SVG('rect',{x:mx.x-80,y:X.y-24,width:160,height:48,rx:6,fill:'none',stroke:'var(--yellow)','stroke-width':1.5}));
  const lX = SVG('text',{x:X.x,y:X.y+5,'text-anchor':'middle','font-size':14,fill:'var(--yellow)','font-weight':600}); lX.textContent='A¹_j'; svg.appendChild(lX);
  // scheme Y
  svg.appendChild(SVG('rect',{x:Y.x-50,y:Y.y-24,width:100,height:48,rx:6,fill:'none',stroke:'var(--blue)','stroke-width':1.5}));
  const lY = SVG('text',{x:Y.x,y:Y.y+5,'text-anchor':'middle','font-size':14,fill:'var(--blue)','font-weight':600}); lY.textContent='Y'; svg.appendChild(lY);
  // π always
  drawArrow(svg,[mx.x,mx.y+28],[X.x,X.y-24],{label:'π',color:'var(--green)',markerId:'co1'});
  // f always
  drawArrow(svg,[mx.x+80,mx.y],[Y.x-50,Y.y],{label:'f',color:'var(--pink)',markerId:'co2'});
  if(step >= 1){
    // factorization
    drawArrow(svg,[X.x+80,X.y],[Y.x-50,Y.y+10],{label:'∃! f̄',color:'var(--cyan)',markerId:'co3',dash:'6 3'});
    out.textContent = 'Unique factorization: f = f̄ ∘ π. On points, f̄ sends j ↦ f(any elliptic curve with that j-invariant).';
  }
}
